package genxsolution.vms.vmsbackend.vehicle_management.vehicle_daily_activity.service;
import genxsolution.vms.vmsbackend.vehicle_management.exception.VehicleResourceNotFoundException; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_daily_activity.dto.*; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_daily_activity.mapper.VehicleDailyActivityMapper; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_daily_activity.repository.VehicleDailyActivityRepository; import org.springframework.stereotype.Service; import java.util.*;
@Service public class VehicleDailyActivityService { private final VehicleDailyActivityRepository repository; private final VehicleDailyActivityMapper mapper; public VehicleDailyActivityService(VehicleDailyActivityRepository repository,VehicleDailyActivityMapper mapper){this.repository=repository;this.mapper=mapper;} public List<VehicleDailyActivityResponse> list(UUID companyId){ return repository.findAll(companyId).stream().map(mapper::toResponse).toList(); } public VehicleDailyActivityResponse getById(UUID id){ return repository.findById(id).map(mapper::toResponse).orElseThrow(() -> new VehicleResourceNotFoundException("VehicleDailyActivity", id.toString())); } public VehicleDailyActivityResponse create(VehicleDailyActivityUpsertRequest r){ return mapper.toResponse(repository.create(r)); } public VehicleDailyActivityResponse update(UUID id,VehicleDailyActivityUpsertRequest r){ return repository.update(id,r).map(mapper::toResponse).orElseThrow(() -> new VehicleResourceNotFoundException("VehicleDailyActivity", id.toString())); } public void delete(UUID id){ if(!repository.delete(id)) throw new VehicleResourceNotFoundException("VehicleDailyActivity", id.toString()); } }
